// ─────────────────────────────────────────────────────────────
//  callAI — FREE, NO API KEY.
//  Calls Pollinations.ai directly from the browser (uses each
//  user's own connection, so it isn't rate-limited like a shared
//  server IP). Falls back to the /api/chat serverless route if the
//  direct call fails (that route can use Ollama or a key if set up).
// ─────────────────────────────────────────────────────────────
// Optional: paste a free token from https://auth.pollinations.ai (register your
// site's domain there too — e.g. your-app.vercel.app). A token/registered
// referrer dramatically reduces the "AI is busy" rate-limit errors. Leave the
// token blank to use the anonymous free tier (still works, just less reliable).
const POLLINATIONS_TOKEN    = ""; // e.g. "xxxxxxxxxxxxxxxx"
const POLLINATIONS_REFERRER = "allbee"; // ideally your deployed domain
// Free models tried in order until one answers.
const POLLINATIONS_MODELS   = ["openai", "openai-fast", "mistral"];

const sleep = (ms) => new Promise((res) => setTimeout(res, ms));

// fetch() with an automatic timeout so a stuck request never hangs the UI.
const fetchWithTimeout = async (url, opts = {}, ms = 35000) => {
  const ctrl = new AbortController();
  const id = setTimeout(() => ctrl.abort(), ms);
  try { return await fetch(url, { ...opts, signal: ctrl.signal }); }
  finally { clearTimeout(id); }
};

// One attempt against a single model.
const callPollinationsModel = async (model, systemPrompt, userMessage) => {
  const body = {
    model,
    messages: [
      { role: "system", content: systemPrompt || "You are a helpful assistant." },
      { role: "user",   content: userMessage },
    ],
    referrer: POLLINATIONS_REFERRER,
    private: true,
  };
  const qs = new URLSearchParams({ referrer: POLLINATIONS_REFERRER });
  if (POLLINATIONS_TOKEN) qs.set("token", POLLINATIONS_TOKEN);
  const headers = { "Content-Type": "application/json" };
  if (POLLINATIONS_TOKEN) headers["Authorization"] = "Bearer " + POLLINATIONS_TOKEN;

  const r = await fetchWithTimeout(
    "https://text.pollinations.ai/openai?" + qs.toString(),
    { method: "POST", headers, body: JSON.stringify(body) },
    22000
  );
  const raw = await r.text();
  if (!r.ok) throw new Error("Free AI HTTP " + r.status);
  let text = "";
  try { text = JSON.parse(raw)?.choices?.[0]?.message?.content || ""; }
  catch { text = raw; }
  if (!text.trim()) throw new Error("Free AI returned empty");
  return text.trim();
};

// ── PRIMARY: your own reliable backend (RECOMMENDED) ─────────────────
// Calls the /api/chat serverless function, which uses a real API key kept
// SECRET on the server (a FREE Groq key works great). This is what makes the
// assistant answer reliably every time. See api/chat.js + the setup steps.
const callViaServer = async (systemPrompt, userMessage) => {
  const res = await fetchWithTimeout("/api/chat", {
    method:  "POST",
    headers: { "Content-Type": "application/json" },
    body:    JSON.stringify({ system: systemPrompt, message: userMessage }),
  }, 45000);
  let data;
  try { data = await res.json(); }
  catch { throw new Error("Server returned non-JSON (status " + res.status + ")."); }
  if (!res.ok || data.error) throw new Error(data && data.error ? data.error : "Server error (HTTP " + res.status + ")");
  if (!data.text || !data.text.trim()) throw new Error("Server returned empty response.");
  return data.text.trim();
};

// ── FALLBACK: free keyless service (no setup, but rate-limited) ───────
// Tries a few free Pollinations models. Used only when the backend route
// above isn't set up yet, or is momentarily failing.
const callPollinationsDirect = async (systemPrompt, userMessage) => {
  let lastErr;
  for (const model of POLLINATIONS_MODELS) {
    try { return await callPollinationsModel(model, systemPrompt, userMessage); }
    catch (e) { lastErr = e; }
  }
  throw lastErr || new Error("Free AI failed");
};

const EMOJI_RE = /[\u{1F000}-\u{1FAFF}\u{2600}-\u{26FF}\u{2700}-\u{2712}\u{2714}\u{2716}-\u{27BF}\u{2B00}-\u{2BFF}\u{2300}-\u{23FF}\u{FE0F}\u{FE0E}\u{200D}]/gu;

// Removes emoji from model output (and tidies the space they leave behind)
// so nothing decorative reaches the screen or the text-to-speech voice.
const stripEmoji = (t) => {
  if (typeof t !== "string") return t;
  return t
    .replace(EMOJI_RE, "\u0000")
    .replace(/[ \t]*\u0000+[ \t]*/g, (m, off, s) => (off === 0 || s[off - 1] === "\n" ? "" : " "))
    .replace(/[ \t]+$/gm, "");
};

const NO_EMOJI_RULE =
  "\n\nIMPORTANT: Do not use any emoji, emoticons or decorative symbols anywhere in your answer. " +
  "Use plain text headings and • bullets only.";

const callAI = async (rawSystemPrompt, userMessage) => {
  const systemPrompt = (rawSystemPrompt || "You are a helpful assistant.") + NO_EMOJI_RULE;
  // 1) Reliable backend first — answers every time once an API key is set up.
  let serverMsg = "";
  try {
    return stripEmoji(await callViaServer(systemPrompt, userMessage));
  } catch (serverErr) {
    serverMsg = (serverErr && serverErr.message) || "unknown";
  }
  // 2) Backend not configured / failed — fall back to the free service.
  try {
    return stripEmoji(await callPollinationsDirect(systemPrompt, userMessage));
  } catch (freeErr) {
    const freeMsg = (freeErr && freeErr.message) || "unknown";
    // Show the REAL reason so the problem can be pinpointed and fixed.
    throw new Error(
      "Couldn't get an answer. Please tap “Try again”. " +
      "[backend: " + serverMsg + "] [free: " + freeMsg + "]"
    );
  }
};
const callClaude = callAI; // alias — all existing calls work unchanged


// ─── GAMIFICATION · PROGRESS · STREAK (Bee levels & points) ──────────────────
const PROGRESS_KEY     = "allbee_progress";
const STREAK_KEY       = "allbee_streak";
const RESUME_KEY       = "allbee_resume";
const INTERVIEW_KEY    = "allbee_interview_scores";
const JOBS_SAVED_KEY   = "allbee_saved_jobs";
const JOBS_APPLIED_KEY = "allbee_applications";
const JOBS_POSTED_KEY  = "allbee_posted_jobs";

const DEFAULT_PROGRESS = { lessonsRead: 0, interviews: 0, labsDone: 0, resumes: 0, jobsApplied: 0, certificates: 0 };

const getProgress = () => {
  try { return { ...DEFAULT_PROGRESS, ...(JSON.parse(localStorage.getItem(PROGRESS_KEY)) || {}) }; }
  catch { return { ...DEFAULT_PROGRESS }; }
};
const bumpProgress = (key, by = 1) => {
  const p = getProgress();
  p[key] = (p[key] || 0) + by;
  try { localStorage.setItem(PROGRESS_KEY, JSON.stringify(p)); } catch { /* silent */ }
  try { syncProgress("Progress: " + key); } catch { /* silent */ }
  return p;
};

const todayStr = () => new Date().toISOString().slice(0, 10);
const getStreak = () => {
  try { return JSON.parse(localStorage.getItem(STREAK_KEY)) || { count: 0, last: null }; }
  catch { return { count: 0, last: null }; }
};
// Call once per app load — grows on consecutive days, resets after a gap.
const updateStreak = () => {
  const s = getStreak();
  const today = todayStr();
  if (s.last === today) return s;
  const yesterday = new Date(Date.now() - 864e5).toISOString().slice(0, 10);
  const next = { count: s.last === yesterday ? (s.count || 0) + 1 : 1, last: today };
  try { localStorage.setItem(STREAK_KEY, JSON.stringify(next)); } catch { /* silent */ }
  try { syncProgress("Daily streak"); } catch { /* silent */ }
  return next;
};

const getInterviewScores = () => {
  try { return JSON.parse(localStorage.getItem(INTERVIEW_KEY)) || {}; }
  catch { return {}; }
};
const saveInterviewScore = (role, score) => {
  const all = getInterviewScores();
  all[role] = Math.max(all[role] || 0, score);
  try { localStorage.setItem(INTERVIEW_KEY, JSON.stringify(all)); } catch { /* silent */ }
  try { syncProgress("Mock interview"); } catch { /* silent */ }
  return all;
};
const bestInterviewScore = () => {
  const vals = Object.values(getInterviewScores());
  return vals.length ? Math.max(...vals) : 0;
};

// Points are derived from real activity so they can never be faked out of sync.
const getPoints = () => {
  const h = getHistory().length;
  const p = getProgress();
  return h * 10 + p.lessonsRead * 15 + p.interviews * 30 + p.labsDone * 20 +
         p.resumes * 25 + p.jobsApplied * 15 + p.certificates * 50;
};

const BEE_LEVELS = [
  { name: "Bronze Bee",  min: 0,    emoji: "", color: "#b45309" },
  { name: "Silver Bee",  min: 250,  emoji: "", color: "#64748b" },
  { name: "Gold Bee",    min: 700,  emoji: "", color: "#d97706" },
  { name: "Diamond Bee", min: 1500, emoji: "", color: "#0891b2" },
  { name: "Queen Bee",   min: 3000, emoji: "", color: "#a855f7" },
];
const getBeeLevel = (points) => {
  let idx = 0;
  for (let i = 0; i < BEE_LEVELS.length; i++) if (points >= BEE_LEVELS[i].min) idx = i;
  const current = BEE_LEVELS[idx];
  const next = BEE_LEVELS[idx + 1] || null;
  const span = next ? next.min - current.min : 1;
  const pct = next ? Math.min(100, Math.round(((points - current.min) / span) * 100)) : 100;
  return { current, next, pct, idx };
};

// Light per-skill progress inferred from what the student has actually asked / practised.
const SKILL_TRACK = [
  { key: "python",  label: "Python",         emoji: "",  match: ["python", "django", "flask"] },
  { key: "excel",   label: "Advanced Excel", emoji: "",  match: ["excel", "vlookup", "pivot", "formula"] },
  { key: "tally",   label: "Tally & GST",    emoji: "",  match: ["tally", "gst", "journal", "ledger", "accounting"] },
  { key: "powerbi", label: "Power BI",       emoji: "",  match: ["power bi", "powerbi", "dax", "dashboard"] },
  { key: "english", label: "Spoken English", emoji: "", match: ["english", "grammar", "speaking", "conversation"] },
  { key: "ai",      label: "AI Tools",       emoji: "",  match: ["prompt", "chatgpt", "automation", "machine learning", "ai tool"] },
];
const getSkillProgress = () => {
  const blob = getHistory().map(h => ((h.input || "") + " " + (h.feature || "")).toLowerCase());
  return SKILL_TRACK.map(s => {
    const hits = blob.filter(t => s.match.some(m => t.includes(m))).length;
    return { ...s, pct: Math.min(100, hits * 18) };
  });
};

// ── Real course progress: which lesson topics the student has actually read ──
// Stored as { [courseId]: { [topic]: true } }. This powers the dashboard's
// "My Learning" progress and the "Lessons read" count (and syncs to the cloud).
const LESSONS_READ_KEY = "allbee_lessons_read";
const getLessonProgress = () => {
  try { return JSON.parse(localStorage.getItem(LESSONS_READ_KEY)) || {}; }
  catch { return {}; }
};
const markLessonRead = (courseId, topic) => {
  if (!courseId || !topic) return;
  const all = getLessonProgress();
  if (!all[courseId]) all[courseId] = {};
  if (all[courseId][topic]) return;            // already counted — don't double-count
  all[courseId][topic] = true;
  try { localStorage.setItem(LESSONS_READ_KEY, JSON.stringify(all)); } catch { /* silent */ }
  bumpProgress("lessonsRead");                 // increments the counter + syncs to cloud
};

// Fisher–Yates shuffle (used for randomising interview & lab questions)
const shuffleArr = (arr) => {
  const b = arr.slice();
  for (let i = b.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    const t = b[i]; b[i] = b[j]; b[j] = t;
  }
  return b;
};

// ═══════════════════════════════════════════════════════════════════════════
//  ADMIN + LIVE CLASS + SHARED CLOUD  (added)
//  ---------------------------------------------------------------------------
//  1) ADMIN_CODE  — secret code YOU (teacher) type to open the Admin page.
//                   CHANGE it to your own secret. Never share with students.
//  2) CLOUD_URL   — paste your Google Apps Script Web App URL (…/exec) here so
//                   every student's progress is saved to your Google Sheet and
//                   the Admin page can see everyone across all devices.
//                   Setup steps are in the file "allbee-apps-script.gs".
//                   Leave it "" to skip — the app still works; the Admin page
//                   will then only show your registered student roster.
//  3) CLOUD_SECRET— must EXACTLY match the SECRET inside your Apps Script.
// ═══════════════════════════════════════════════════════════════════════════
const ADMIN_CODE          = "allbee-admin-2025";     // CHANGE THIS
const CLOUD_URL           = "";                       // paste your …/exec URL
const CLOUD_SECRET        = "allbee-secret-key";      // match Apps Script SECRET
const ALLBEE_DEFAULT_ROOM = "AllBeeLiveClassRoom";    // default Jitsi room name

const cloudEnabled = () => !!CLOUD_URL;
const currentUser  = () => { try { return JSON.parse(localStorage.getItem(USER_KEY)); } catch { return null; } };

// Fire a POST to the Apps Script backend. text/plain avoids a CORS preflight,
// which Apps Script web apps do not answer — this is the reliable pattern.
const cloudPost = async (payload) => {
  if (!CLOUD_URL) return null;
  try {
    const res = await fetch(CLOUD_URL, {
      method: "POST",
      headers: { "Content-Type": "text/plain;charset=utf-8" },
      body: JSON.stringify({ secret: CLOUD_SECRET, ...payload }),
    });
    try { return await res.json(); } catch { return null; }
  } catch { return null; }
};

const cloudGet = async (action) => {
  if (!CLOUD_URL) return null;
  try {
    const url = CLOUD_URL + "?secret=" + encodeURIComponent(CLOUD_SECRET)
              + "&action=" + encodeURIComponent(action) + "&t=" + Date.now();
    const res = await fetch(url);
    return await res.json();
  } catch { return null; }
};

// A full snapshot of THIS logged-in student's progress, for the shared sheet.
const buildSnapshot = () => {
  const u = currentUser();
  if (!u || u.isAdmin) return null;
  const p   = getProgress();
  const pts = getPoints();
  return {
    phone:         (u.phone || "").replace(/\D/g, "").slice(-10),
    name:          u.name   || "",
    email:         u.email  || "",
    course:        u.course || "",
    points:        pts,
    level:         getBeeLevel(pts).current.name,
    streak:        getStreak().count || 0,
    aiQuestions:   getHistory().length,
    lessonsRead:   p.lessonsRead   || 0,
    interviews:    p.interviews    || 0,
    bestInterview: bestInterviewScore(),
    labsDone:      p.labsDone      || 0,
    resumes:       p.resumes       || 0,
    jobsApplied:   p.jobsApplied   || 0,
    certificates:  p.certificates  || 0,
    lastActive:    new Date().toISOString(),
  };
};

// Debounced upsert — many quick actions collapse into one network write.
let _allbeeSyncTimer = null;
const syncProgress = (event) => {
  if (!cloudEnabled()) return;
  const snap = buildSnapshot();
  if (!snap || !snap.phone) return;
  clearTimeout(_allbeeSyncTimer);
  _allbeeSyncTimer = setTimeout(() => {
    cloudPost({ action: "upsertProgress", student: snap, event: event || "" });
  }, 500);
};

// ── Teacher notes: admin writes them, students read them (shared via the Sheet)
const NOTES_CACHE_KEY = "allbee_notes_v1";
const noteKey = (course, topic) => String(course || "") + "::" + String(topic || "");
const getNotesLocal  = () => { try { return JSON.parse(localStorage.getItem(NOTES_CACHE_KEY)) || {}; } catch { return {}; } };
const saveNotesLocal = (map) => { try { localStorage.setItem(NOTES_CACHE_KEY, JSON.stringify(map)); } catch { /* silent */ } };
// Pull all teacher notes from the cloud (falls back to the local cache offline).
const fetchTeacherNotes = async () => {
  if (cloudEnabled()) {
    const r = await cloudGet("notes");
    if (r && Array.isArray(r.notes)) {
      const map = {};
      r.notes.forEach(n => { if (n && n.text) map[noteKey(n.course, n.topic)] = n.text; });
      saveNotesLocal(map);
      return map;
    }
  }
  return getNotesLocal();
};
// Save/replace one note (empty text deletes it). Updates local cache + cloud.
const setTeacherNote = async (course, topic, text) => {
  const map = getNotesLocal();
  const k = noteKey(course, topic);
  const t = (text || "").trim();
  if (t) map[k] = t; else delete map[k];
  saveNotesLocal(map);
  if (cloudEnabled()) { try { await cloudPost({ action: "setNote", note: { course, topic, text: t } }); } catch { /* silent */ } }
  return map;
};

// ── Admin job postings (shared via the Sheet; students only see, admin posts) ─
const JOBS_CACHE_KEY = "allbee_jobs_cache";
const getJobsLocal  = () => { try { return JSON.parse(localStorage.getItem(JOBS_CACHE_KEY)) || []; } catch { return []; } };
const saveJobsLocal = (arr) => { try { localStorage.setItem(JOBS_CACHE_KEY, JSON.stringify(arr)); } catch { /* */ } };
const fetchCloudJobs = async () => {
  if (cloudEnabled()) {
    const r = await cloudGet("jobs");
    if (r && Array.isArray(r.jobs)) { saveJobsLocal(r.jobs); return r.jobs; }
  }
  return getJobsLocal();
};
const setCloudJob = async (job) => {
  const arr = getJobsLocal().filter(j => j.id !== job.id);
  arr.unshift(job); saveJobsLocal(arr);
  if (cloudEnabled()) { try { await cloudPost({ action: "setJob", job }); } catch { /* */ } }
  return arr;
};
const deleteCloudJob = async (id) => {
  const arr = getJobsLocal().filter(j => j.id !== id); saveJobsLocal(arr);
  if (cloudEnabled()) { try { await cloudPost({ action: "deleteJob", id }); } catch { /* */ } }
  return arr;
};

// ── Certificates: student requests, teacher approves (shared via the Sheet) ──
const normPhone10 = (p) => String(p || "").replace(/\D/g, "").slice(-10);
const fetchCerts = async () => {
  if (cloudEnabled()) { const r = await cloudGet("certs"); if (r && Array.isArray(r.certs)) return r.certs; }
  return [];
};
const requestCert = async (phone, name, course) => {
  if (cloudEnabled()) { try { await cloudPost({ action: "requestCert", cert: { phone: normPhone10(phone), name, course } }); } catch { /* */ } }
};
const decideCert = async (phone, course, status) => {
  if (cloudEnabled()) { try { await cloudPost({ action: "decideCert", cert: { phone: normPhone10(phone), course, status } }); } catch { /* */ } }
};

// ── Local log of class recordings made ON THIS device ────────────────────────
const REC_LOG_KEY  = "allbee_recordings";
const getRecordings = () => { try { return JSON.parse(localStorage.getItem(REC_LOG_KEY)) || []; } catch { return []; } };
const logRecording  = (r) => {
  const l = getRecordings();
  l.unshift({ ...r, id: Date.now() });
  try { localStorage.setItem(REC_LOG_KEY, JSON.stringify(l.slice(0, 200))); } catch { /* silent */ }
};

// small time helpers for the Admin page
const isTodayISO = (iso) => !!iso && new Date(iso).toISOString().slice(0, 10) === new Date().toISOString().slice(0, 10);
const agoStr = (iso) => {
  if (!iso) return "never";
  const s = Math.floor((Date.now() - new Date(iso).getTime()) / 1000);
  if (isNaN(s)) return "—";
  if (s < 60)    return "just now";
  if (s < 3600)  return Math.floor(s / 60) + "m ago";
  if (s < 86400) return Math.floor(s / 3600) + "h ago";
  return Math.floor(s / 86400) + "d ago";
};

